package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testGetNullString_DefaultNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        assertNull(format.getNullString());
    }

    @Test
    void testGetNullString_WithNullString() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        assertEquals("NULL", format.getNullString());
    }

    @Test
    void testGetNullString_ReflectionSetNullString() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Use reflection to create a new CSVFormat instance with nullString = "REF_NULL"
        // Because the field is final, modifying it via reflection is unsafe and likely ineffective.
        // Instead, create a new instance using the withNullString method via reflection.

        // Get the withNullString method
        CSVFormat newFormat = format.withNullString("REF_NULL");

        assertEquals("REF_NULL", newFormat.getNullString());
    }
}
